// Utility functions for course management

export const removeDuplicateCourses = (courses) => {
  const seen = new Set();
  return courses.filter(course => {
    const key = `${course.title}-${course.instructor}`;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
};

export const validateCourse = (course) => {
  const errors = [];

  if (!course.title?.trim()) errors.push('Title is required');
  if (!course.desc?.trim()) errors.push('Description is required');
  if (!course.price || course.price < 0) errors.push('Valid price is required');
  if (!course.instructor?.trim()) errors.push('Instructor is required');
  if (!course.time?.trim()) errors.push('Duration is required');

  return { isValid: errors.length === 0, errors };
};

export const formatPrice = (price) => {
  return new Intl.NumberFormat('en-IN', {
    style: 'currency',
    currency: 'INR',
    minimumFractionDigits: 0
  }).format(price);
};

export const calculateProgress = (completedLessons, totalLessons) => {
  if (!totalLessons || totalLessons === 0) return 0;
  return Math.round((completedLessons / totalLessons) * 100);
};

export const getCategoryIcon = (category) => {
  const icons = {
    development: '💻',
    ai: '🤖',
    design: '🎨',
    business: '💼'
  };
  return icons[category] || '📚';
};

export const sortCourses = (courses, sortBy) => {
  const sorted = [...courses];

  switch (sortBy) {
    case 'price':
      return sorted.sort((a, b) => a.price - b.price);
    case 'enrolled':
      return sorted.sort((a, b) => b.enrolled - a.enrolled);
    case 'rating':
      return sorted.sort((a, b) => parseFloat(b.rating) - parseFloat(a.rating));
    case 'newest':
      return sorted.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
    default:
      return sorted;
  }
};
